---
import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import SEO from '../components/SEO.astro';
import { VisualEditing } from '@sanity/astro/visual-editing';
import { getAlternateUrl, type Lang } from '../lib/navigation';

interface Props {
  title: string;
  description?: string;
  lang?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
} = Astro.props;

const alternateUrl = getAlternateUrl(Astro.url.pathname, lang as Lang);
const absoluteAlternateUrl = new URL(alternateUrl, Astro.site ?? 'https://ficcc.org').href;

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <SEO title={title} description={description} lang={lang} alternateUrl={absoluteAlternateUrl} />
    <link rel="preconnect" href="https://cdn.sanity.io" crossorigin />
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <a href="#main-content" class="skip-to-content">Skip to main content</a>
    <Header lang={lang} langToggleHref={alternateUrl} />
    <slot />
    <Footer lang={lang} />
    {isVisualEditingEnabled && <VisualEditing enabled={true} />}
    <script>
      document.addEventListener('click', (e) => {
        const toggle = (e.target as HTMLElement).closest('.lang-toggle') as HTMLAnchorElement | null;
        if (toggle) {
          const targetLang = toggle.href.includes('/zh') ? 'zh' : 'en';
          document.cookie = 'lang-pref=' + targetLang + ';path=/;max-age=31536000;SameSite=Lax';
        }
      });
    </script>
  </body>
</html>

<style is:global>
  .skip-to-content {
    position: absolute;
    left: -9999px;
    top: auto;
    width: 1px;
    height: 1px;
    overflow: hidden;
    z-index: 9999;
    padding: var(--space-3) var(--space-6);
    background: var(--color-ink);
    color: var(--color-bg);
    font-family: var(--font-body);
    font-size: var(--text-base);
    text-decoration: none;
    border-radius: var(--radius-sm, 0.25rem);
  }

  .skip-to-content:focus-visible {
    position: fixed;
    left: var(--space-4);
    top: var(--space-4);
    width: auto;
    height: auto;
    overflow: visible;
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }
</style>

---
interface Props {
  title: string;
  description?: string;
  canonicalUrl?: string;
  ogImage?: string;
  ogType?: string;
  lang?: string;
  jsonLd?: Record<string, unknown>;
  alternateUrl?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  canonicalUrl,
  ogImage = '/og-default.png',
  ogType = 'website',
  lang = 'en',
  jsonLd,
  alternateUrl,
} = Astro.props;

const siteUrl = Astro.site ?? new URL('https://ficcc.org');
const canonical = canonicalUrl ?? new URL(Astro.url.pathname, siteUrl).href;
const absoluteOgImage = new URL(ogImage, siteUrl).href;

const localeMap: Record<string, string> = {
  en: 'en_US',
  zh: 'zh_CN',
};
const ogLocale = localeMap[lang] ?? 'en_US';

const defaultJsonLd = {
  '@context': 'https://schema.org',
  '@type': 'Church',
  name: 'FICCC — Fellowship of Ithaca Chinese Christians Church',
  description,
  url: canonical,
};

const structuredData = jsonLd ?? defaultJsonLd;
---

<title>{title}</title>
<meta name="description" content={description} />
<link rel="canonical" href={canonical} />

{alternateUrl && (
  <>
    <link rel="alternate" hreflang="en" href={lang === 'en' ? canonical : alternateUrl} />
    <link rel="alternate" hreflang="zh" href={lang === 'zh' ? canonical : alternateUrl} />
    <link rel="alternate" hreflang="x-default" href={lang === 'en' ? canonical : alternateUrl} />
  </>
)}

<!-- Open Graph -->
<meta property="og:title" content={title} />
<meta property="og:description" content={description} />
<meta property="og:url" content={canonical} />
<meta property="og:image" content={absoluteOgImage} />
<meta property="og:type" content={ogType} />
<meta property="og:locale" content={ogLocale} />

<!-- Twitter Card -->
<meta name="twitter:card" content="summary_large_image" />
<meta name="twitter:title" content={title} />
<meta name="twitter:description" content={description} />
<meta name="twitter:image" content={absoluteOgImage} />

<!-- JSON-LD Structured Data -->
<script type="application/ld+json" set:html={JSON.stringify(structuredData)} />

import { defineConfig } from 'astro/config';
import sitemap from '@astrojs/sitemap';
import sanity from '@sanity/astro';
import react from '@astrojs/react';
import vercel from '@astrojs/vercel';

export default defineConfig({
  site: 'https://ficcc.org',
  // Astro 5 removed output:'hybrid' — static + adapter is the equivalent,
  // enabling per-page SSR opt-in via `export const prerender = false`.
  output: 'static', // hybrid equivalent with adapter
  adapter: vercel(),
  integrations: [
    sitemap(),
    sanity({
      projectId: import.meta.env.SANITY_PROJECT_ID || 'placeholder',
      dataset: import.meta.env.SANITY_DATASET || 'production',
      useCdn: false, // false for static builds per @sanity/astro docs
      stega: {
        studioUrl: import.meta.env.PUBLIC_SANITY_PREVIEW_URL || 'http://localhost:3333',
      },
    }),
    react(),
  ],
  i18n: {
    defaultLocale: 'en',
    locales: ['en', 'zh'],
    routing: {
      prefixDefaultLocale: false,
    },
  },
});

