const { createWriteStream } = require('fs');
const zlib = require('zlib');

const width = 1200, height = 630;

// Build raw RGBA rows (dark navy background #1a1a2e with white centered text area hint)
const rows = [];
for (let y = 0; y < height; y++) {
  const row = Buffer.alloc(1 + width * 3); // filter byte + RGB
  row[0] = 0; // no filter
  for (let x = 0; x < width; x++) {
    const off = 1 + x * 3;
    // Dark navy background
    row[off] = 0x1a;
    row[off+1] = 0x1a;
    row[off+2] = 0x2e;
  }
  rows.push(row);
}
const rawData = Buffer.concat(rows);

// PNG helpers
function crc32(buf) {
  let c = 0xffffffff;
  const table = new Int32Array(256);
  for (let n = 0; n < 256; n++) {
    let v = n;
    for (let k = 0; k < 8; k++) v = v & 1 ? 0xedb88320 ^ (v >>> 1) : v >>> 1;
    table[n] = v;
  }
  for (let i = 0; i < buf.length; i++) c = table[(c ^ buf[i]) & 0xff] ^ (c >>> 8);
  return (c ^ 0xffffffff) >>> 0;
}

function chunk(type, data) {
  const len = Buffer.alloc(4); len.writeUInt32BE(data.length);
  const typeB = Buffer.from(type, 'ascii');
  const payload = Buffer.concat([typeB, data]);
  const crcB = Buffer.alloc(4); crcB.writeUInt32BE(crc32(payload));
  return Buffer.concat([len, payload, crcB]);
}

// IHDR
const ihdr = Buffer.alloc(13);
ihdr.writeUInt32BE(width, 0);
ihdr.writeUInt32BE(height, 4);
ihdr[8] = 8; // bit depth
ihdr[9] = 2; // color type RGB
ihdr[10] = 0; ihdr[11] = 0; ihdr[12] = 0;

// Compress pixel data
const deflated = zlib.deflateSync(rawData, { level: 9 });

const png = Buffer.concat([
  Buffer.from([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a]), // PNG signature
  chunk('IHDR', ihdr),
  chunk('IDAT', deflated),
  chunk('IEND', Buffer.alloc(0))
]);

require('fs').writeFileSync('public/og-default.png', png);
console.log('Created', png.length, 'bytes');
